const body = $input.first().json.body || $input.first().json;

// --- Platform validation ---
const allowedPlatforms = ['shopify', 'woocommerce'];
const platform = (body.platform || $vars.DEFAULT_PLATFORM || 'shopify').toLowerCase();
if (!allowedPlatforms.includes(platform)) {
  throw new Error(`Invalid platform "${platform}". Must be: ${allowedPlatforms.join(' | ')}`);
}

// --- File source validation ---
if (!body.fileUrl && !body.filename) {
  throw new Error('Provide either fileUrl (remote image) or filename (for binary upload).');
}

// --- Filename & MIME detection ---
const filename = body.filename || body.fileUrl?.split('?')[0].split('/').pop() || 'product.jpg';
const ext = filename.split('.').pop()?.toLowerCase() || 'jpg';
const mimeMap = { jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', webp: 'image/webp', gif: 'image/gif', avif: 'image/avif' };
const mimeType = mimeMap[ext] || 'image/jpeg';

// --- SKU sanitisation ---
const rawSku = body.sku || '';
const sku = rawSku.toUpperCase().replace(/[^A-Z0-9\-_]/g, '').trim() || `SKU-${Date.now()}`;

// --- Price coercion ---
const price = parseFloat(body.price) || 0;
const compareAtPrice = parseFloat(body.compareAtPrice) || null;
if (price < 0) throw new Error('Price cannot be negative.');

// --- Inventory ---
const inventory = parseInt(body.inventory, 10);
const safeInventory = isNaN(inventory) ? 1 : Math.max(0, inventory);

// --- Tags ---
const tagsRaw = body.tags || '';
const tagsArray = tagsRaw.split(',').map(t => t.trim()).filter(Boolean);

return [{
  json: {
    // Source
    filename,
    fileUrl: body.fileUrl || null,
    mimeType,
    // Platform
    platform,
    publishImmediately: body.publishImmediately !== false,
    // Product fields
    sku,
    price,
    compareAtPrice,
    vendor: body.vendor || '',
    productType: body.productType || '',
    inventory: safeInventory,
    weight: parseFloat(body.weight) || null,
    tags: tagsArray,
    // Pass-through for AI context
    userTitle: body.title || '',
    userDescription: body.description || '',
    // Meta
    receivedAt: new Date().toISOString()
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate & Enrich Payload').first().json;

const imageUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!imageUrl) {
  throw new Error('Upload to URL returned no public URL. Raw response: ' + JSON.stringify(uploadResp));
}

// Ensure URL is HTTPS (some CDNs return HTTP)
const secureUrl = imageUrl.replace(/^http:\/\//, 'https://');

return [{
  json: {
    ...meta,
    imageUrl: secureUrl,
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

