const aiRaw = $input.first().json;
const productData = $('Extract Image URL').first().json;

// --- Parse AI response ---
let ai;
try {
  const raw = aiRaw.message?.content || aiRaw.choices?.[0]?.message?.content || aiRaw.content || aiRaw.text;
  ai = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Failed to parse GPT-4o JSON response: ' + e.message);
}

// --- Validate essentials ---
if (!ai.title) throw new Error('GPT-4o did not return a product title.');

// --- Merge user-provided tags with AI tags (deduplicated) ---
const allTags = [...new Set([
  ...productData.tags,
  ...(ai.suggestedTags || [])
])].slice(0, 15); // Most platforms cap at 15 tags

// --- Build clean URL handle ---
const handle = (ai.handle || ai.title)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .trim();

// --- Shopify status ---
const shopifyStatus = productData.publishImmediately ? 'active' : 'draft';

// --- WooCommerce status ---
const wcStatus = productData.publishImmediately ? 'publish' : 'draft';

return [{
  json: {
    // Pass-through
    platform: productData.platform,
    imageUrl: productData.imageUrl,
    sku: productData.sku,
    price: productData.price,
    compareAtPrice: productData.compareAtPrice,
    vendor: productData.vendor,
    productType: productData.productType || ai.suggestedCategory,
    inventory: productData.inventory,
    weight: productData.weight,
    uploadId: productData.uploadId,

    // AI-generated
    title: productData.userTitle || ai.title,
    seoTitle: ai.seoTitle,
    description: ai.description,
    shortDescription: ai.shortDescription,
    bulletFeatures: ai.bulletFeatures || [],
    category: ai.suggestedCategory,
    tags: allTags,
    metaDescription: ai.metaDescription,
    handle,
    marketingBlurb: ai.marketingBlurb,
    confidenceScore: ai.confidenceScore || null,

    // Platform-specific computed
    shopifyStatus,
    wcStatus,

    generatedAt: new Date().toISOString()
  }
}];

const platformResp = $input.first().json;
const productData = $('Parse & Merge AI Product Data').first().json;

// Normalise Shopify vs WooCommerce response shapes
const isShopify = productData.platform === 'shopify';

const productId = isShopify
  ? (platformResp.product?.id || platformResp.id)
  : (platformResp.id);

const productUrl = isShopify
  ? `https://${platformResp.product?.handle || productData.handle}.myshopify.com/products/${platformResp.product?.handle || productData.handle}`
  : (platformResp.permalink || `${platformResp.link || ''}`);

const imageUrl = isShopify
  ? (platformResp.product?.images?.[0]?.src || productData.imageUrl)
  : (platformResp.images?.[0]?.src || productData.imageUrl);

if (!productId) {
  throw new Error(`${productData.platform} did not return a product ID. Response: ${JSON.stringify(platformResp).slice(0, 300)}`);
}

return [{
  json: {
    success: true,
    platform: productData.platform,
    productId: String(productId),
    productUrl,
    imageUrl,
    title: productData.title,
    sku: productData.sku,
    price: productData.price,
    compareAtPrice: productData.compareAtPrice,
    category: productData.category,
    tags: productData.tags,
    handle: productData.handle,
    inventory: productData.inventory,
    marketingBlurb: productData.marketingBlurb,
    confidenceScore: productData.confidenceScore,
    publishStatus: productData.shopifyStatus || productData.wcStatus,
    generatedAt: productData.generatedAt,
    createdAt: new Date().toISOString()
  }
}];

